import type { GlobalFlags } from '@/types';
import type { Wallets } from '@/wallet';
import type { coreRequestSchema } from './schemas/core';
import type z from 'zod';

export interface RequestContext {
  wallets: Wallets;
  flags: GlobalFlags;
}

export enum RequestMethod {
  GET = 'GET',
  POST = 'POST',
  PUT = 'PUT',
  DELETE = 'DELETE',
  PATCH = 'PATCH',
}

export type RequestInput = z.infer<typeof coreRequestSchema> & {
  headers: Record<string, string>;
  body?: string | undefined;
};
